SELECT * FROM token_usage_daily
WHERE tenant_id = #{tenantId}
  AND usage_date BETWEEN #{startDate} AND #{endDate}
ORDER BY usage_date DESC, model_name

SELECT * FROM token_usage_daily
WHERE tenant_id = #{tenantId}
  AND usage_date = #{usageDate}
  AND model_name = #{modelName}
LIMIT 1
